20	CMRC_DECLARE(rc);
21	
22	using namespace uhd::usrp::cal;
23	namespace rc = cmrc::rc;
24	namespace fs = std::filesystem;
25	
26	namespace {
27	constexpr char LOG_ID[]  = "CAL::DATABASE";
28	constexpr char CAL_EXT[] = ".cal";
29	//! This value is just for sanity checking. We pick a value (in bytes) that we
30	// are guaranteed to never exceed. Its only purpose is to avoid loading files
31	// that can't possibly be valid cal data based on the filesize. This can avoid
32	// someone bringing down a UHD session by trying to import a huge file, because
33	// we first load it entirely into heap space, and then deserialize it from there.
34	constexpr size_t CALDATA_MAX_SIZE = 10 * 1024 * 1024; // 10 MiB
35	
36	/******************************************************************************
37	 * RC implementation
38	 *****************************************************************************/
39	//! Helper: Map a cal resource key into a source::RC path name
40	std::string get_cal_path_rc(const std::string& key)
41	{
42	    return std::string("cal/") + key + CAL_EXT;
43	}
44	
45	//! Return true if a cal data resource with given key exists
46	//
47	// The serial parameter is ignored, as serial numbers should, by definition, not
48	// matter for RC data
49	bool has_cal_data_rc(const std::string& key, const std::string&)
50	{
51	    auto fs = rc::get_filesystem();
52	    const std::string cal_path(get_cal_path_rc(key));
53	    UHD_LOG_TRACE(LOG_ID, "Checking for resource " << cal_path);
54	    return fs.is_file(cal_path);
55	}
56	
57	//! Return a byte array for a given cal resource
58	std::vector<uint8_t> get_cal_data_rc(const std::string& key, const std::string&)
59	{
60	    try {
61	        auto fs   = rc::get_filesystem();
62	        auto file = fs.open(get_cal_path_rc(key));
63	        return std::vector<uint8_t>(file.cbegin(), file.cend());
64	    } catch (const std::system_error&) {
65	        throw uhd::key_error(std::string("Unable to open resource with key: ") + key);
66	    }
67	}
68	
69	/******************************************************************************
70	 * Filesystem implementation
71	 *****************************************************************************/
72	//! Helper: Check a path exists, or create it if not. Does not create recursively,
73	// think mkdir, not mkdir -p.
74	void check_or_create_dir(fs::path dir)
75	{
76	    if (fs::exists(dir)) {
77	        if (fs::is_directory(dir)) {
78	            return;
79	        }
80	        UHD_LOG_ERROR(LOG_ID, "Path exists, but is not a directory: " << dir);
81	        throw uhd::runtime_error("Path exists, but is not a directory!");
82	    }
83	
84	    if (!fs::create_directory(dir)) {
85	        UHD_LOG_ERROR(LOG_ID, "Cannot create cal data directory: " << dir);
86	        throw uhd::runtime_error("Cannot create cal data directory!");
87	    }
88	    UHD_LOG_DEBUG(LOG_ID, "Created directory: " << dir);
89	}
90	
91	//! Make sure the calibration storage directory exists.
92	//
93	// The path returned by uhd::get_cal_data_path() might not exist (e.g., when run
94	// for the first time). This directory must be created before we try writing to
95	// it, or we won't be able to open the file.
96	//
97	// C++ doesn't have a mkdir -p equivalent, so we check the parent directory and
98	// the directory itself, in that order. Most of the time, the cal data path is
99	// in $XDG_DATA_HOME/uhd/cal_data. We assume that $XDG_DATA_HOME exists, and
100	// then first check $XDG_DATA_HOME/uhd, then $XDG_DATA_HOME/uhd/cal_data.
101	//
102	// This will not work if the user sets $UHD_CAL_DATA_PATH to an arbitrary path
103	// that requires multiple levels of directories to be created, but they will get
104	// a clear error message in that case.
105	void assert_cal_dir_exists()
106	{
107	    const auto cal_path = fs::path(uhd::get_cal_data_path());
108	    if (!cal_path.parent_path().empty()) {
109	        check_or_create_dir(cal_path.parent_path());
110	    }
111	    check_or_create_dir(cal_path);
112	}
113	
114	//! Helper: Map a cal resource key into a filesystem path name
115	// (relative to get_cal_data_path())
116	std::string get_cal_path_fs(const std::string& key, const std::string& serial)
117	{
118	    return key + "_" + serial + CAL_EXT;
119	}
120	
121	//! Return true if a cal data resource with given key exists
122	bool has_cal_data_fs(const std::string& key, const std::string& serial)
123	{
124	    auto const cal_file_path =
125	        fs::path(uhd::get_cal_data_path()) / get_cal_path_fs(key, serial);
126	    UHD_LOG_TRACE(LOG_ID, "Checking for file at " << cal_file_path.string());
127	    // We might want to check readability also
128	    return fs::exists(cal_file_path) && fs::is_regular_file(cal_file_path);
129	}
130	
131	//! Return a byte array for a given filesystem resource
132	std::vector<uint8_t> get_cal_data_fs(const std::string& key, const std::string& serial)
133	{
134	    if (!has_cal_data_fs(key, serial)) {
135	        throw uhd::key_error(
136	            std::string("Cannot find cal file for key=") + key + ", serial=" + serial);
137	    }
138	    const auto cal_file_path =
139	        fs::path(uhd::get_cal_data_path()) / get_cal_path_fs(key, serial);
140	    // We read the filesize first to do a sanity check (is this file small
141	    // enough to reasonably be cal data?) and also to pre-allocate heap space in
142	    // which we'll load the full data for future deserialization.
143	    const size_t filesize = fs::file_size(cal_file_path);
144	    if (filesize > CALDATA_MAX_SIZE) {
145	        throw uhd::key_error(
146	            std::string("The following cal data file exceeds maximum size limitations: ")
147	            + cal_file_path.string());
148	    }
149	    std::vector<uint8_t> result(filesize, 0);
150	    std::ifstream file(cal_file_path.string(), std::ios::binary);
151	    UHD_LOG_TRACE(LOG_ID, "Reading " << filesize << " bytes from " << cal_file_path);
152	    file.read(reinterpret_cast<char*>(&result[0]), filesize);
153	    return result;
154	}
155	
156	} // namespace
157	
158	/******************************************************************************
159	 * Flash/EEPROM implementation
160	 *****************************************************************************/
161	// Access to non-volatile memory is device-specific. Instead of implementing
162	// anything here, we allow devices to register callbacks to look up cal data
163	// from their EEPROMs / flash memories.
164	using lookup_registry_type =
165	    std::vector<std::pair<database::has_data_fn_type, database::get_data_fn_type>>;
166	UHD_SINGLETON_FCN(lookup_registry_type, get_flash_lookup_registry);
167	
168	bool has_cal_data_flash(const std::string& key, const std::string& serial)
169	{
170	    for (auto& data_fn_pair : get_flash_lookup_registry()) {
171	        if (data_fn_pair.first(key, serial)) {
172	            return true;
173	        }
174	    }
175	    return false;
176	}
177	
178	std::vector<uint8_t> get_cal_data_flash(const std::string& key, const std::string& serial)
179	{
180	    for (auto& data_fn_pair : get_flash_lookup_registry()) {
181	        if (data_fn_pair.first(key, serial)) {
182	            return data_fn_pair.second(key, serial);
183	        }
184	    }
185	    // No data? Then throw:
186	    throw uhd::key_error(
187	        std::string("Cannot find flash cal data for key=") + key + ", serial=" + serial);
188	}
189	
190	
191	/******************************************************************************
192	 * Function lookup
193	 *****************************************************************************/
194	typedef bool (*has_cal_data_fn)(const std::string&, const std::string&);
195	typedef std::vector<uint8_t> (*get_cal_data_fn)(const std::string&, const std::string&);
196	typedef std::tuple<source, has_cal_data_fn, get_cal_data_fn> cal_data_fn_tuple;
197	// These are in order of priority!
198	// clang-format off
199	constexpr std::array<cal_data_fn_tuple, 3> data_fns{{
200	    cal_data_fn_tuple{source::FILESYSTEM, &has_cal_data_fs,    &get_cal_data_fs   },
201	    cal_data_fn_tuple{source::FLASH,      &has_cal_data_flash, &get_cal_data_flash},
202	    cal_data_fn_tuple{source::RC,         &has_cal_data_rc,    &get_cal_data_rc   }
203	}};
204	// clang-format on
205	
206	
207	/******************************************************************************
208	 * cal::database implementation
209	 *****************************************************************************/
210	std::vector<uint8_t> database::read_cal_data(
211	    const std::string& key, const std::string& serial, const source source_type)
212	{
213	    for (auto& data_fn : data_fns) {
214	        if (source_type == source::ANY || source_type == std::get<0>(data_fn)) {
215	            if (std::get<1>(data_fn)(key, serial)) {
216	                return std::get<2>(data_fn)(key, serial);
217	            }
218	        }
219	    }
220	
221	    const std::string err_msg =
222	        std::string("Calibration Data not found for: key=") + key + ", serial=" + serial;
223	    UHD_LOG_ERROR(LOG_ID, err_msg);
224	    throw uhd::key_error(err_msg);
225	}
226	
227	bool database::has_cal_data(
228	    const std::string& key, const std::string& serial, const source source_type)
229	{
230	    for (auto& data_fn : data_fns) {
231	        if (source_type == source::ANY || source_type == std::get<0>(data_fn)) {
232	            if (std::get<1>(data_fn)(key, serial)) {
233	                return true;
234	            }
235	        }
236	    }
237	
238	    return false;
239	}
240	
241	void database::write_cal_data(const std::string& key,
242	    const std::string& serial,
243	    const std::vector<uint8_t>& cal_data,
244	    const std::string& backup_ext)
245	{
246	    assert_cal_dir_exists();
247	
248	    const auto cal_file_path =
249	        (fs::path(uhd::get_cal_data_path()) / get_cal_path_fs(key, serial)).string();
250	
251	    if (fs::exists(cal_file_path)) {
252	        const auto ext = backup_ext.empty() ? std::to_string(time(NULL)) : backup_ext;
253	        const auto cal_file_path_backup = fs::path(uhd::get_cal_data_path())
254	                                          / (get_cal_path_fs(key, serial) + "." + ext);
255	        UHD_LOG_WARNING(LOG_ID,
256	            "Calibration data already exists for key: `"
257	                << key << "' serial: `" << serial
258	                << "'. Backing up to: " << cal_file_path_backup);
259	        fs::rename(fs::path(cal_file_path), cal_file_path_backup);
260	    }
261	
262	    std::ofstream file(cal_file_path, std::ios::binary);
263	    UHD_LOG_DEBUG(LOG_ID, "Writing to " << cal_file_path);
264	    file.write(reinterpret_cast<const char*>(cal_data.data()), cal_data.size());
265	}
266	
267	void database::register_lookup(has_data_fn_type has_cal_data,
268	    get_data_fn_type get_cal_data,
269	    const source source_type)
270	{
271	    UHD_ASSERT_THROW(source_type == source::FLASH);
272	    get_flash_lookup_registry().push_back({has_cal_data, get_cal_data});
273	}
