131	/***********************************************************************
132	 * Compute power of a tone
133	 **********************************************************************/
134	static inline double compute_tone_dbrms(const std::vector<samp_type>& samples,
135	    const double freq) // freq is fractional
136	{
137	    // shift the samples so the tone at freq is down at DC
138	    // and average the samples to measure the DC component
139	    samp_type average = 0;
140	    for (size_t i = 0; i < samples.size(); i++)
141	        average += samp_type(std::polar(1.0, -freq * tau * i)) * samples[i];
142	
143	    return 20 * std::log10(std::abs(average / float(samples.size())));
144	}
