180	/***********************************************************************
181	 * Data capture routine
182	 **********************************************************************/
183	static void capture_samples(uhd::usrp::multi_usrp::sptr usrp,
184	    uhd::rx_streamer::sptr rx_stream,
185	    std::vector<samp_type>& buff,
186	    const size_t nsamps_requested)
187	{
188	    buff.resize(nsamps_requested);
189	    uhd::rx_metadata_t md;
190	
191	    // Right after the stream is started, there will be transient data.
192	    // That transient data is discarded and only "good" samples are returned.
193	    size_t nsamps_to_discard = size_t(usrp->get_rx_rate() * 0.001); // 1ms to be discarded
194	    std::vector<samp_type> discard_buff(nsamps_to_discard);
195	
196	    uhd::stream_cmd_t stream_cmd(uhd::stream_cmd_t::STREAM_MODE_NUM_SAMPS_AND_DONE);
197	    stream_cmd.num_samps  = buff.size() + nsamps_to_discard;
198	    stream_cmd.stream_now = true;
199	    usrp->issue_stream_cmd(stream_cmd);
200	    size_t num_rx_samps = 0;
201	
202	    // Discard the transient samples.
203	    rx_stream->recv(&discard_buff.front(), discard_buff.size(), md);
204	    if (md.error_code != uhd::rx_metadata_t::ERROR_CODE_NONE) {
205	        throw std::runtime_error(std::string("Receiver error: ") + md.strerror());
206	    }
207	
208	    // Now capture the data we want
209	    num_rx_samps = rx_stream->recv(&buff.front(), buff.size(), md);
210	
211	    // validate the received data
212	    if (md.error_code != uhd::rx_metadata_t::ERROR_CODE_NONE) {
213	        throw std::runtime_error(std::string("Receiver error: ") + md.strerror());
214	    }
215	
216	    // we can live if all the data didnt come in
217	    if (num_rx_samps > buff.size() / 2) {
218	        buff.resize(num_rx_samps);
219	        return;
220	    }
221	    if (num_rx_samps != buff.size())
222	        throw std::runtime_error("did not get all the samples requested");
223	}
