263	/***********************************************************************
264	 * Function to find optimal RX gain setting (for the current frequency)
265	 **********************************************************************/
266	UHD_INLINE void set_optimal_rx_gain(uhd::usrp::multi_usrp::sptr usrp,
267	    uhd::rx_streamer::sptr rx_stream,
268	    double wave_freq = 0.0,
269	    double gain_step = 3.0)
270	{
271	    const double gain_step_threshold = gain_step * 0.5;
272	    const double actual_rx_rate      = usrp->get_rx_rate();
273	    const double actual_tx_freq      = usrp->get_tx_freq();
274	    const double actual_rx_freq      = usrp->get_rx_freq();
275	    const double bb_tone_freq        = actual_tx_freq - actual_rx_freq + wave_freq;
276	    const size_t nsamps              = size_t(actual_rx_rate / default_fft_bin_size);
277	
278	    std::vector<samp_type> buff(nsamps);
279	    uhd::gain_range_t rx_gain_range = usrp->get_rx_gain_range();
280	    double rx_gain                  = rx_gain_range.start() + gain_step;
281	    double curr_dbrms               = 0.0;
282	    double prev_dbrms               = 0.0;
283	    double delta                    = 0.0;
284	
285	    // No sense in setting the gain where this is no gain range
286	    if (rx_gain_range.stop() - rx_gain_range.start() < gain_step)
287	        return;
288	
289	    // The algorithm below cycles through the RX gain range
290	    // looking for the point where the signal begins to get
291	    // clipped and the gain begins to be compressed.  It does
292	    // this by looking for the gain setting where the increase
293	    // in the tone is less than the gain step by more than the
294	    // gain compression threshold (curr - prev < gain - threshold).
295	    // This routine starts searching at the bottom of the gain range
296	    // rather than the top in order to minimize the chances of
297	    // exposing frontend components to a dangerous amount of power
298	    // from the incoming signal.
299	
300	    // Initialize prev_dbrms value
301	    usrp->set_rx_gain(rx_gain);
302	    capture_samples(usrp, rx_stream, buff, nsamps);
303	    prev_dbrms = compute_tone_dbrms(buff, bb_tone_freq / actual_rx_rate);
304	    rx_gain += gain_step;
305	
306	    // First, get the signal above the noise floor
307	    while (rx_gain <= rx_gain_range.stop()) {
308	        usrp->set_rx_gain(rx_gain);
309	        capture_samples(usrp, rx_stream, buff, nsamps);
310	        curr_dbrms = compute_tone_dbrms(buff, bb_tone_freq / actual_rx_rate);
311	        delta      = curr_dbrms - prev_dbrms;
312	
313	        // Check that the signal power is not already high
314	        if (curr_dbrms >= 0)
315	            break;
316	        // Check that the signal power has increased as the gain increases
317	        if (delta >= gain_step - gain_step_threshold)
318	            break;
319	
320	        prev_dbrms = curr_dbrms;
321	        rx_gain += gain_step;
322	    }
323	
324	    // Find RX gain where signal begins to clip
325	    while (rx_gain <= rx_gain_range.stop()) {
326	        usrp->set_rx_gain(rx_gain);
327	        capture_samples(usrp, rx_stream, buff, nsamps);
328	        curr_dbrms = compute_tone_dbrms(buff, bb_tone_freq / actual_rx_rate);
329	        delta      = curr_dbrms - prev_dbrms;
330	
331	        // check if the gain is compressed beyone the threshold
332	        if (delta < gain_step - gain_step_threshold)
333	            break; // if so, we are done
334	
335	        prev_dbrms = curr_dbrms;
336	        rx_gain += gain_step;
337	    }
338	
339	    // The rx_gain value at this point is the gain setting where clipping
340	    // occurs or the gain setting that is just beyond the gain range.
341	    // The gain is reduced by 2 steps to make sure it is within the range and
342	    // under the point where it is clipped with enough room to make adjustments.
343	    rx_gain -= 2 * gain_step;
344	
345	    // Make sure the gain is within the range.
346	    rx_gain = rx_gain_range.clip(rx_gain);
347	
348	    // Finally, set the gain.
349	    usrp->set_rx_gain(rx_gain);
350	}
