352	/***********************************************************************
353	 * Transmit thread
354	 **********************************************************************/
355	static void tx_thread(std::atomic_flag* transmit,
356	    uhd::usrp::multi_usrp::sptr usrp,
357	    uhd::tx_streamer::sptr tx_stream,
358	    const double tx_wave_freq,
359	    const double tx_wave_ampl,
360	    const std::optional<double> tx_gain,
361	    std::atomic<bool>& transmit_started)
362	{
363	    // increase thread priority for TX to prevent underruns
364	    uhd::set_thread_priority_safe();
365	
366	    constexpr size_t chan = 0;
367	    const auto tx_info    = usrp->get_usrp_tx_info(chan);
368	
369	    if (tx_gain.has_value()) {
370	        usrp->set_tx_gain(tx_gain.value());
371	    } else if (tx_info.has_key("tx_default_cal_gain")) {
372	        usrp->set_tx_gain(std::stod(tx_info["tx_default_cal_gain"]));
