8	#include "usrp_cal_utils.hpp"
9	#include <uhd/utils/safe_main.hpp>
10	#include <boost/math/special_functions/round.hpp>
11	#include <boost/program_options.hpp>
12	#include <chrono>
13	#include <complex>
14	#include <cstdlib>
15	#include <ctime>
16	#include <functional>
17	#include <iostream>
18	
19	namespace po = boost::program_options;
20	
21	/***********************************************************************
22	 * Tune RX and TX routine
23	 **********************************************************************/
24	static double tune_rx_and_tx(
25	    uhd::usrp::multi_usrp::sptr usrp, const double tx_lo_freq, const double rx_offset)
26	{
27	    // tune the transmitter with no cordic
28	    uhd::tune_request_t tx_tune_req(tx_lo_freq);
29	    tx_tune_req.dsp_freq_policy = uhd::tune_request_t::POLICY_MANUAL;
30	    tx_tune_req.dsp_freq        = 0;
31	    usrp->set_tx_freq(tx_tune_req);
32	
33	    // tune the receiver
34	    double rx_freq        = usrp->get_tx_freq() - rx_offset;
35	    double min_fe_rx_freq = usrp->get_fe_rx_freq_range().start();
36	    double max_fe_rx_freq = usrp->get_fe_rx_freq_range().stop();
37	    uhd::tune_request_t rx_tune_req(rx_freq);
38	    rx_tune_req.dsp_freq_policy = uhd::tune_request_t::POLICY_MANUAL;
39	    rx_tune_req.dsp_freq        = 0;
40	    if (rx_freq < min_fe_rx_freq)
41	        rx_tune_req.dsp_freq = rx_freq - min_fe_rx_freq;
42	    else if (rx_freq > max_fe_rx_freq)
43	        rx_tune_req.dsp_freq = rx_freq - max_fe_rx_freq;
44	    usrp->set_rx_freq(rx_tune_req);
45	
46	    wait_for_lo_lock(usrp);
47	
48	    return usrp->get_tx_freq();
49	}
50	
51	/***********************************************************************
52	 * Main
53	 **********************************************************************/
54	int UHD_SAFE_MAIN(int argc, char* argv[])
55	{
56	    std::string args, subdev, serial;
57	    double tx_wave_freq, tx_wave_ampl, tx_gain, rx_offset;
58	    double freq_start, freq_stop, freq_step;
59	    size_t nsamps;
60	    double precision;
61	
62	    po::options_description desc("Allowed options");
63	    // clang-format off
64	    desc.add_options()
65	        ("help", "help message")
66	        ("verbose", "enable some verbose")
67	        ("args", po::value<std::string>(&args)->default_value(""), "device address args [default = \"\"]")
68	        ("subdev", po::value<std::string>(&subdev), "Subdevice specification (default: first subdevice, often 'A')")
69	        ("tx_wave_freq", po::value<double>(&tx_wave_freq)->default_value(507.123e3), "Transmit wave frequency in Hz")
70	        ("tx_wave_ampl", po::value<double>(&tx_wave_ampl)->default_value(0.7), "Transmit wave amplitude")
71	        ("tx_gain", po::value<double>(&tx_gain), "Tx gain in dB (do not specify for default)")
72	        ("rx_offset", po::value<double>(&rx_offset)->default_value(.9344e6), "RX LO offset from the TX LO in Hz")
73	        ("freq_start", po::value<double>(&freq_start), "Frequency start in Hz (do not specify for default)")
74	        ("freq_stop", po::value<double>(&freq_stop), "Frequency stop in Hz (do not specify for default)")
75	        ("freq_step", po::value<double>(&freq_step)->default_value(default_freq_step), "Step size for LO sweep in Hz")
76	        ("nsamps", po::value<size_t>(&nsamps), "Samples per data capture")
77	        ("precision", po::value<double>(&precision)->default_value(default_precision), "Correction precision (default=0.0001)")
78	    ;
79	    // clang-format on
80	
81	    po::variables_map vm;
82	    po::store(po::parse_command_line(argc, argv, desc), vm);
83	    po::notify(vm);
84	
85	    // print the help message
86	    if (vm.count("help")) {
87	        std::cout << boost::format("USRP Generate TX IQ Balance Calibration Table %s")
88	                         % desc
89	                  << std::endl;
90	        std::cout << "This application measures leakage between RX and TX on a "
91	                     "transceiver daughterboard to self-calibrate.\n"
92	                     "Note: Not all daughterboards support this feature. Refer to the "
93	                     "UHD manual for details.\n"
94	                  << std::endl;
95	        return EXIT_FAILURE;
96	    }
97	
98	    // Create a USRP device
99	    uhd::usrp::multi_usrp::sptr usrp = setup_usrp_for_cal(args, subdev, serial);
100	
101	    if (not vm.count("nsamps"))
102	        nsamps = size_t(usrp->get_rx_rate() / default_fft_bin_size);
103	
104	    // create a receive streamer
105	    uhd::stream_args_t stream_args("fc32"); // complex floats
106	    uhd::rx_streamer::sptr rx_stream = usrp->get_rx_stream(stream_args);
107	
108	    // create a transmit streamer
109	    uhd::tx_streamer::sptr tx_stream = usrp->get_tx_stream(stream_args);
110	
111	    // create a transmitter thread
112	    std::atomic_flag transmit = ATOMIC_FLAG_INIT;
113	    std::atomic<bool> transmit_started(false);
114	    transmit.test_and_set();
115	    auto transmitter = std::thread(std::bind(&tx_thread,
116	        &transmit,
117	        usrp,
118	        tx_stream,
119	        tx_wave_freq,
120	        tx_wave_ampl,
121	        vm.count("tx_gain") ? std::optional<double>(tx_gain) : std::optional<double>(),
122	        std::ref(transmit_started)));
123	
124	    // Wait for tx_thread to start transmitting
125	    size_t iter = 0;
126	    while (!transmit_started.load()) {
127	        std::this_thread::sleep_for(std::chrono::milliseconds(100));
128	        if (++iter > 100) {
129	            std::cerr << "TX thread did not start transmitting within 10 seconds."
130	                      << std::endl;
131	            return EXIT_FAILURE;
132	        }
133	    }
