110	    /**************************************************************************
111	     * Container API (Serialization/Deserialization)
112	     *************************************************************************/
113	    std::vector<uint8_t> serialize() override
114	    {
115	        // This is a magic value to estimate the amount of space the builder will
116	        // have to reserve on top of the coeff data.
117	        // Worst case is we get this too low, and the builder will have to do a
118	        // single reallocation later.
119	        constexpr size_t RESERVE_HDR_BYTES = 20;
120	        const size_t initial_size_bytes =
121	            sizeof(IQCalCoeff) * _coeffs.size() + RESERVE_HDR_BYTES;
122	        flatbuffers::FlatBufferBuilder builder(initial_size_bytes);
123	        // Convert the coefficients to a vector of IQCalCoeff
124	        std::vector<IQCalCoeff> fb_coeffs;
125	        fb_coeffs.reserve(_coeffs.size());
126	        std::transform(_coeffs.cbegin(),
127	            _coeffs.cend(),
128	            std::back_inserter(fb_coeffs),
129	            [&](const coeffs_type::value_type& coeff) {
130	                const double freq     = coeff.first;
131	                const auto this_coeff = coeff.second;
132	                return IQCalCoeff(freq,
133	                    this_coeff.real(),
134	                    this_coeff.imag(),
135	                    _supp.count(freq) ? _supp.at(freq).first : 0.0,
136	                    _supp.count(freq) ? _supp.at(freq).second : 0.0);
137	            });
138	        // Now load it all into the FlatBuffer
139	        const auto metadata = CreateMetadataDirect(builder,
140	            _name.c_str(),
141	            _serial.c_str(),
142	            _timestamp,
143	            VERSION_MAJOR,
144	            VERSION_MINOR);
145	        auto cal_table      = CreateIQCalCoeffsDirect(builder, metadata, &fb_coeffs);
146	        FinishIQCalCoeffsBuffer(builder, cal_table);
147	        const size_t table_size = builder.GetSize();
148	        const uint8_t* table    = builder.GetBufferPointer();
149	        return std::vector<uint8_t>(table, table + table_size);
150	    }
151	
152	    // This will amend the existing table. If that's not desired, then it is
153	    // necessary to call clear() ahead of time.
154	    void deserialize(const std::vector<uint8_t>& data) override
155	    {
156	        auto verifier = flatbuffers::Verifier(data.data(), data.size());
157	        if (!VerifyIQCalCoeffsBuffer(verifier)) {
158	            throw uhd::runtime_error("iq_cal: Invalid data provided!");
159	        }
160	        auto cal_table = GetIQCalCoeffs(static_cast<const void*>(data.data()));
161	        // TODO we can handle this more nicely
162	        UHD_ASSERT_THROW(cal_table->metadata()->version_major() == VERSION_MAJOR);
163	        _name       = std::string(cal_table->metadata()->name()->c_str());
164	        _serial     = std::string(cal_table->metadata()->serial()->c_str());
165	        _timestamp  = cal_table->metadata()->timestamp();
166	        auto coeffs = cal_table->coeffs();
167	        for (auto it = coeffs->begin(); it != coeffs->end(); ++it) {
168	            _coeffs[it->freq()] = {it->coeff_real(), it->coeff_imag()};
169	            // Suppression levels are really not necessary for runtime.
170	            // TODO: Come up with a way to skip this step when loading data for
171	            // runtime (and not future storage)
172	            _supp[it->freq()] = {it->suppression_abs(), it->suppression_delta()};
173	        }
174	    }
